SELECT process_name, version
FROM process_models
WHERE status = 'published';

SELECT COUNT(process_model_id) AS count_of_models, '2023' AS year
FROM process_models
WHERE created_date LIKE '2023-%';

SELECT process_name
FROM process_models
ORDER BY process_name;

SELECT status, COUNT(process_model_id) AS count
FROM process_models
GROUP BY status;
